document.addEventListener("DOMContentLoaded",()=>{const e=window.lpCertCacheTools,t=document.querySelector(".lp-cert-cache-tools__delete");if(!e||!t)return;const n=t.closest(".lp-cert-cache-tools"),o=document.querySelector(".learn-press-settings-form .submit, .submit");n&&o&&o.parentNode.insertBefore(n,o),t.addEventListener("click",async()=>{if(window.confirm(e.confirmMessage)){t.disabled=!0,t.textContent=e.deletingLabel;try{const t=await fetch(e.ajaxUrl,{method:"POST",credentials:"same-origin",body:new URLSearchParams({action:"lp_cert_delete_all_images",nonce:e.nonce})}),n=await t.json();window.alert(n.success?n.data.message:e.errorMessage)}catch(t){window.alert(e.errorMessage)}finally{t.disabled=!1,t.textContent=e.buttonLabel}}})});